class Widget:
    def __init__(self, name, color):
        self.name = name
        self.color = color

    def __repr__(self):
        return f'Widget({self.name!r}, {self.color!r})'

    # BUG: registry is defined *after* make_default tries to read it via cls
    # and there's a typo between class attr and access
    @classmethod
    def make_default(cls):
        return cls.registry['default']

    REGISTRY = {'default': None}  # uppercased but accessed as lowercase


def main():
    Widget.REGISTRY['default'] = Widget('x', 'blue')
    w = Widget.make_default()
    print(w)


if __name__ == '__main__':
    main()
